'use client';

import type { FC } from 'react';

import { Handle } from './components/handle';
import { HandleRoot } from './components/handle-root';
import { Item } from './components/item';
import { Provider } from './components/provider';
import { Root } from './components/root';
import { useReactCompareSlider } from './hooks';
import type { ReactCompareSliderDetailedProps } from './types';

export const ReactCompareSlider: FC<ReactCompareSliderDetailedProps> = ({
  boundsPadding,
  browsingContext,
  changePositionOnHover,
  clip,
  defaultPosition,
  disabled,
  handle,
  itemOne,
  itemTwo,
  keyboardIncrement,
  onPositionChange,
  onlyHandleDraggable,
  portrait,
  transition,
  ...props
}) => {
  const contextProps = useReactCompareSlider({
    boundsPadding,
    browsingContext,
    changePositionOnHover,
    clip,
    defaultPosition,
    disabled,
    keyboardIncrement,
    onPositionChange,
    onlyHandleDraggable,
    portrait,
    transition,
  });

  return (
    <Provider {...contextProps}>
      <Root {...props}>
        <Item item="itemOne">{itemOne}</Item>
        <Item item="itemTwo">{itemTwo}</Item>
        <HandleRoot>{handle || <Handle />}</HandleRoot>
      </Root>
    </Provider>
  );
};

'use client';

import { useCallback, useEffect, useLayoutEffect, useRef, useState } from 'react';

import { KeyboardEventKeys } from './components/internal-hooks';
import { ReactCompareSliderClip, ReactCompareSliderCssVars } from './consts';
import { register } from './register';
import type {
  SetPositionFromBoundsProps,
  UseReactCompareSliderProps,
  UseReactCompareSliderReturn,
} from './types';

register();

const DEFAULT_TRANSITION = '0.15s ease-out';

const getDefaultOnlyHandleDraggable = () => !!globalThis.matchMedia?.('(pointer: coarse)')?.matches;

/**
 * Hook to completely control the slider including all event handlers and state.
 * This is automatically used by the `ReactCompareSlider` component.
 * Only use this if you are building your own slider using the `react-compare-slider/components` module.
 */
export const useReactCompareSlider = ({
  boundsPadding = '0px',
  browsingContext = globalThis,
  changePositionOnHover = false,
  clip = ReactCompareSliderClip.all,
  defaultPosition = 50,
  disabled = false,
  keyboardIncrement = '5%',
  onlyHandleDraggable = getDefaultOnlyHandleDraggable(),
  onPositionChange,
  portrait = false,
  transition: transitionProp,
}: UseReactCompareSliderProps = {}): UseReactCompareSliderReturn => {
  /** DOM node of the root element. */
  const rootRef = useRef<HTMLDivElement>(null);
  /** DOM node of the handle container. */
  const handleRootRef = useRef<HTMLDivElement>(null);
  /** Current position as a percentage value. */
  const position = useRef(defaultPosition);
  /** Whether user is currently dragging. */
  const [isDragging, setIsDragging] = useState(false);
  /** Whether the `transition` property can be applied. */
  const [canTransition, setCanTransition] = useState(true);
  /** Target container for pointer events. */
  const [interactiveTarget, setInteractiveTarget] = useState<HTMLElement | null>(null);
  /** Motion-safe default that can update after server rendering and when user preference changes. */
  const [defaultTransition, setDefaultTransition] = useState('none');
  const transition = transitionProp ?? defaultTransition;

  useEffect(() => {
    const media = globalThis.matchMedia?.('(prefers-reduced-motion: no-preference)');
    if (!media) return;

    const syncTransition = () => setDefaultTransition(media.matches ? DEFAULT_TRANSITION : 'none');
    syncTransition();
    media.addEventListener('change', syncTransition);

    return () => media.removeEventListener('change', syncTransition);
  }, []);

  const setPosition = useCallback(
    (nextPosition: number) => {
      const appliedPosition = Math.min(Math.max(nextPosition, 0), 100);

      rootRef.current?.style.setProperty(ReactCompareSliderCssVars.rawPosition, `${appliedPosition}%`);
      handleRootRef.current?.setAttribute('aria-valuenow', `${Math.round(appliedPosition)}`);
      position.current = appliedPosition;

      onPositionChange?.(appliedPosition);
    },
    [onPositionChange],
  );

  /** Set position using pointer coords. */
  const setPositionFromBounds = useCallback(
    function updateInternal({ x, y }: SetPositionFromBoundsProps) {
      const rootElement = rootRef.current as HTMLDivElement;
      const { width, height, top, left } = rootElement.getBoundingClientRect();

      // Early out when component has zero bounds.
      if (width === 0 || height === 0) return;

      const pixelPosition = portrait ? y - top - browsingContext.scrollY : x - left - browsingContext.scrollX;
      const nextPosition = (pixelPosition / (portrait ? height : width)) * 100;
      setPosition(nextPosition);
    },
    [browsingContext, portrait, setPosition],
  );

  /** Handle mouse/touch down. */
  const onPointerDown = useCallback(
    (ev: PointerEvent) => {
      ev.preventDefault();

      // Only handle left mouse button (touch events also use 0).
      if (disabled || ev.button !== 0) return;

      setPositionFromBounds({ x: ev.pageX, y: ev.pageY });
      setIsDragging(true);
      setCanTransition(true);
    },
    [disabled, setPositionFromBounds],
  );

  /** Handle mouse/touch move. */
  const onPointerMove = useCallback(
    function moveCall(ev: PointerEvent) {
      setCanTransition(false);
      setPositionFromBounds({ x: ev.pageX, y: ev.pageY });
    },
    [setPositionFromBounds],
  );

  /** Handle mouse/touch up. */
  const onPointerUp = useCallback((_ev: PointerEvent) => {
    setIsDragging(false);
    setCanTransition(true);
  }, []);

  const onTouchEnd = useCallback((_ev: TouchEvent) => {
    setIsDragging(false);
    setCanTransition(true);
  }, []);

  const onHandleRootClick = useCallback(
    (ev: PointerEvent) => {
      ev.preventDefault();
      if (disabled) return;
      (ev.currentTarget as HTMLDivElement)?.focus();
    },
    [disabled],
  );

  /** Handle keyboard movment. */
  const onHandleRootKeyDown = useCallback(
    (ev: KeyboardEvent) => {
      if (disabled || !Object.values(KeyboardEventKeys).includes(ev.key as KeyboardEventKeys)) {
        return;
      }

      ev.preventDefault();
      setCanTransition(true);

      const incrementPercentage =
        typeof keyboardIncrement === 'string'
          ? Number.parseFloat(keyboardIncrement)
          : (keyboardIncrement / (rootRef.current?.getBoundingClientRect().width as number)) * 100;

      const isIncrement = portrait
        ? ev.key === KeyboardEventKeys.ARROW_LEFT || ev.key === KeyboardEventKeys.ARROW_DOWN
        : ev.key === KeyboardEventKeys.ARROW_RIGHT || ev.key === KeyboardEventKeys.ARROW_UP;

      const nextPosition = isIncrement
        ? position.current + incrementPercentage
        : position.current - incrementPercentage;

      setPosition(nextPosition);
    },
    [disabled, keyboardIncrement, portrait, setPosition],
  );

  // Set target container for pointer events.
  useLayoutEffect(() => {
    setInteractiveTarget(onlyHandleDraggable ? handleRootRef.current : rootRef.current);
  }, [onlyHandleDraggable]);

  // Resync position when defaultPosition changes.
  useEffect(() => {
    setPosition(defaultPosition);
  }, [defaultPosition, setPosition]);

  return {
    // Direct props
    boundsPadding,
    browsingContext,
    changePositionOnHover,
    clip,
    defaultPosition,
    disabled,
    keyboardIncrement,
    onlyHandleDraggable,
    portrait,
    transition,
    // Events
    onHandleRootKeyDown,
    onPointerDown,
    onPointerMove,
    onPointerUp,
    onTouchEnd,
    onHandleRootClick,
    // State
    canTransition,
    isDragging,
    position,
    // Setters
    setPosition,
    setPositionFromBounds,
    // Elements
    rootRef,
    handleRootRef,
    interactiveTarget,
  };
};

import type { ComponentProps, ReactNode, RefObject } from 'react';

import type { ReactCompareSliderClipValue } from './consts';

/** Slider position property. */
export type ReactCompareSliderPosition = number;

/** Common props shared between components. */
export type ReactCompareSliderCommonProps = {
  /**
   * Divider position.
   * @default 50
   */
  defaultPosition?: ReactCompareSliderPosition;

  /**
   * Whether to disable slider movement (items are still interactable).
   * @default false
   */
  disabled?: boolean;

  /**
   * Whether to use portrait (vertical) orientation.
   * @default false
   */
  portrait?: boolean;

  /**
   * Shorthand CSS `transition` property to apply to handle movement. The specific CSS property
   * to transition **must not** be provided.
   * @example '.5s ease-in-out'
   */
  transition?: string;
};

/** Props for the pre-built `ReactCompareSlider` component. */
export type ReactCompareSliderProps = ReactCompareSliderCommonProps & {
  /**
   * CSS unit amount to limit the slideable bounds on the X-axis (landscape) or Y-axis (portrait).
   * @example '20rem'
   * @default '0px'
   */
  boundsPadding?: string;

  /**
   * Custom browsing context to use instead of the global `window` object.
   * @default globalThis
   */
  browsingContext?: typeof globalThis | Window | WindowProxy;

  /**
   * Whether the slider should follow the pointer on hover.
   * @default false
   */
  changePositionOnHover?: boolean;

  /**
   * Whether to clip `itemOne`, `itemTwo` or `all` items.
   * @default all
   */
  clip?: ReactCompareSliderClipValue;

  /** Custom handle component. */
  handle?: ReactNode;

  /** First item to show. */
  itemOne: ReactNode;

  /** Second item to show. */
  itemTwo: ReactNode;

  /**
   * Percentage or pixel amount to move when the slider handle is focused and keyboard arrow is pressed.
   * @default '5%'
   */
  keyboardIncrement?: number | `${number}%`;

  /**
   * Whether to only change position when handle is interacted with (useful for touch devices).
   * @default false
   */
  onlyHandleDraggable?: boolean;

  /** Callback on position change with position as percentage. */
  onPositionChange?: (position: ReactCompareSliderPosition) => void;
};

/** `ReactCompareSliderProps` and all valid `div` element props. */
export type ReactCompareSliderDetailedProps = ReactCompareSliderProps &
  Omit<ComponentProps<'div'>, 'children'>;

export type UseReactCompareSliderProps = Omit<ReactCompareSliderProps, 'handle' | 'itemOne' | 'itemTwo'>;

export type SetPositionFromBoundsProps = {
  /** X coordinate to update to (landscape). */
  x: number;
  /** Y coordinate to update to (portrait). */
  y: number;
};

export type UseReactCompareSliderReturn = Required<
  Pick<
    ReactCompareSliderProps,
    | 'boundsPadding'
    | 'browsingContext'
    | 'changePositionOnHover'
    | 'clip'
    | 'defaultPosition'
    | 'disabled'
    | 'keyboardIncrement'
    | 'onlyHandleDraggable'
    | 'portrait'
  >
> &
  Pick<ReactCompareSliderProps, 'transition'> & {
    // Events
    /** Handler fired on the `interactiveTarget` `pointerdown` event. */
    onPointerDown: (event: PointerEvent) => void;
    /** Handler fired on the `rootRef` `pointermove` event when the user `isDragging`. */
    onPointerMove: (event: PointerEvent) => void;
    /** Handler fired on the `interactiveTarget` `pointerup` event. */
    onPointerUp: (event: PointerEvent) => void;
    /** Handler fired on the `interactiveTarget` `touchend` event. */
    onTouchEnd: (event: TouchEvent) => void;
    /** Handler fired on the `handleRootRef` `click` event. */
    onHandleRootClick: (event: PointerEvent) => void;
    /** Handler fired on the `handleRootRef` `keydown` event when the element is focused. */
    onHandleRootKeyDown: (event: KeyboardEvent) => void;
    // State
    /** Whether the `transition` property should be applied. */
    canTransition: boolean;
    /** Whether the user is currently dragging the slider. */
    isDragging: boolean;
    /** Ref with the current position. */
    position: RefObject<ReactCompareSliderPosition>;
    // Setters
    /** Set the position directly as a percentage. */
    setPosition: (nextPosition: number) => void;
    /** Set the position from the coords of an event. */
    setPositionFromBounds: (props: SetPositionFromBoundsProps) => void;
    // Elements
    /** Root element. */
    rootRef: RefObject<HTMLDivElement | null>;
    /** The direct parent element of the `handle` component. */
    handleRootRef: RefObject<HTMLDivElement | null>;
    /**
     * The target element for pointer events.
     * This defaults to the `rootRef` element and switches to the `handleRootRef` element when `onlyHandleDraggable` is `true`.
     */
    interactiveTarget: HTMLElement | null;
  };

export const ReactCompareSliderClip = {
  all: 'all',
  itemOne: 'itemOne',
  itemTwo: 'itemTwo',
} as const;

export type ReactCompareSliderClipValue =
  (typeof ReactCompareSliderClip)[keyof typeof ReactCompareSliderClip];

export const ReactCompareSliderCssVars = {
  /** The unclamped position of the slider as a percentage. */
  rawPosition: '--rcs-raw-position',
  /** The clamped position of the slider with bounds padding applied. */
  currentPosition: '--rcs-current-position',
  /** The `boundsPadding` prop value. */
  boundsPadding: '--rcs-bounds-padding',
  /** The color of the handle border and arrows. */
  handleColor: '--rcs-handle-color',
} as const;

'use client';

import { ReactCompareSliderCssVars } from './consts';

export const register = () => {
  try {
    if (typeof CSS !== 'undefined') {
      /**
       * We use a custom property to optimise the transition performance of the slider. It ensures the
       * transitions fire smoothly at the exact same time on different elements. Otherwise, the handle
       * and item transitions may not move in sync. This is especially noticeable in Safari.
       */
      CSS.registerProperty({
        name: ReactCompareSliderCssVars.rawPosition,
        syntax: '<percentage>',
        inherits: true,
        initialValue: '50%',
      });
    }
  } catch {}
};

'use client';

import type { ComponentProps, CSSProperties, FC } from 'react';

import { useReactCompareSliderContext } from './provider';
import { ReactCompareSliderCssVars } from '../consts';

type ThisArrowProps = {
  /** Whether to flip the arrow direction. */
  flip?: boolean;
};

const ThisArrow: FC<ThisArrowProps> = ({ flip }) => {
  const style: CSSProperties = {
    width: '0.85rem',
    height: '0.85rem',
    clipPath: 'polygon(100% 0%, 100% 100%, 30% 50%)',
    rotate: flip ? '180deg' : '0deg',
    // We use `outline` instead of `border` to ensure that all line colours match in high contrast mode.
    outline: `0.5rem solid var(${ReactCompareSliderCssVars.handleColor})`,
    outlineOffset: '-0.5rem',
  };

  return <div aria-hidden="true" className="__rcs-handle-arrow" style={style} />;
};

/** Props for `ReactCompareSliderHandle`. */
export type HandleProps = {
  /** Optional styles for the circular element in the middle of the handle. */
  buttonStyle?: CSSProperties;
  /** Optional styles for lines either side of the handle button. */
  linesStyle?: CSSProperties;
};

export type HandleDetailedProps = ComponentProps<'div'> & HandleProps;

/**
 * Default `handle` of the `ReactCompareSlider` component. This should be placed within the `HandleRoot`
 * component when building your own slider.
 */
export const Handle: FC<HandleDetailedProps> = ({
  className = '__rcs-handle-root',
  buttonStyle,
  linesStyle,
  style,
  ...props
}) => {
  const { disabled, portrait } = useReactCompareSliderContext();

  const appliedStyle = {
    boxSizing: 'border-box',
    position: 'relative',
    display: 'inline-flex',
    flexDirection: portrait ? 'row' : 'column',
    placeItems: 'center',
    width: portrait ? '100%' : undefined,
    height: portrait ? undefined : '100%',
    cursor: disabled ? 'not-allowed' : portrait ? 'ns-resize' : 'ew-resize',
    pointerEvents: 'none',
    [ReactCompareSliderCssVars.handleColor]: 'rgba(255, 255, 255, 1)',
    ...style,
  } as CSSProperties;

  const appliedLinesStyle: CSSProperties = {
    flexGrow: 1,
    height: portrait ? 2 : '100%',
    width: portrait ? '100%' : 2,
    // We use `outline` instead of `border` to ensure that all line colours match in high contrast mode.
    outline: `1px solid var(${ReactCompareSliderCssVars.handleColor})`,
    outlineOffset: -1,
    pointerEvents: 'auto',
    boxShadow: '0 0 4px rgba(0,0,0,.5)',
    ...linesStyle,
  };

  const appliedButtonStyle: CSSProperties = {
    // Prevents the arrows from pointing at each other in RTL.
    direction: 'ltr',
    display: 'grid',
    gridAutoFlow: 'column',
    gap: '0.5rem',
    placeContent: 'center',
    flexShrink: 0,
    width: '3.5rem',
    height: '3.5rem',
    borderRadius: '50%',
    border: `2px solid var(${ReactCompareSliderCssVars.handleColor})`,
    color: 'inherit',
    pointerEvents: 'auto',
    backdropFilter: 'blur(0.5rem)',
    WebkitBackdropFilter: 'blur(0.5rem)', // For Safari.
    backgroundColor: 'rgba(0, 0, 0, 0.125)',
    boxShadow: '0 0 4px rgba(0,0,0,.35)',
    transform: portrait ? 'rotate(90deg)' : undefined,
    ...buttonStyle,
  };

  return (
    <div data-rcs="handle" {...props} className={className} style={appliedStyle}>
      <div className="__rcs-handle-line" style={appliedLinesStyle} />
      <div className="__rcs-handle-button" style={appliedButtonStyle}>
        <ThisArrow />
        <ThisArrow flip />
      </div>
      <div className="__rcs-handle-line" style={appliedLinesStyle} />
    </div>
  );
};

'use client';

import type { ComponentProps, CSSProperties, FC } from 'react';

import { EVENT_CAPTURE_PARAMS, useEventListener } from './internal-hooks';
import { useReactCompareSliderContext } from './provider';
import { ReactCompareSliderCssVars } from '../consts';

export type HandleRootProps = ComponentProps<'div'>;

/** Container to control the handle's position. */
export const HandleRoot: FC<HandleRootProps> = ({ style, ...props }) => {
  const { disabled, portrait, position, handleRootRef, onHandleRootClick, onHandleRootKeyDown } =
    useReactCompareSliderContext();

  const appliedStyle: CSSProperties = {
    WebkitAppearance: 'none',
    MozAppearance: 'none',
    WebkitTapHighlightColor: 'transparent',
    boxSizing: 'border-box',
    position: 'absolute',
    display: 'flex',
    flexDirection: portrait ? 'row' : 'column',
    placeItems: 'center',
    contain: 'layout',
    top: portrait ? '-50%' : undefined,
    left: portrait ? undefined : `-50%`,
    width: '100%',
    height: '100%',
    background: 'none',
    border: 0,
    padding: 0,
    pointerEvents: 'none',
    appearance: 'none',
    zIndex: 1,
    translate: portrait
      ? `0 var(${ReactCompareSliderCssVars.currentPosition}) 0`
      : `var(${ReactCompareSliderCssVars.currentPosition}) 0 0`,
    backfaceVisibility: 'hidden',
    willChange: 'translate',
    ...style,
  };

  useEventListener('keydown', onHandleRootKeyDown, handleRootRef.current, EVENT_CAPTURE_PARAMS);
  useEventListener('click', onHandleRootClick, handleRootRef.current, EVENT_CAPTURE_PARAMS);

  return (
    <div
      ref={handleRootRef}
      tabIndex={disabled ? -1 : 0}
      aria-label="Click and drag or focus and use arrow keys to change the position of the slider"
      aria-orientation={portrait ? 'vertical' : 'horizontal'}
      aria-valuemin={0}
      aria-valuemax={100}
      aria-valuenow={position.current}
      aria-disabled={disabled}
      data-rcs="handle-root"
      role="slider"
      style={appliedStyle}
      {...props}
    />
  );
};

'use client';

import type { ComponentProps, CSSProperties, FC } from 'react';

import { useReactCompareSliderContext } from './provider';
import {
  ReactCompareSliderClip,
  type ReactCompareSliderClipValue,
  ReactCompareSliderCssVars,
} from '../consts';
import type { ReactCompareSliderProps } from '../types';

type GetClipPathProps = Pick<ReactCompareSliderProps, 'portrait'> & {
  itemClip?: Extract<ReactCompareSliderClipValue, 'itemOne' | 'itemTwo'>;
};

const getClipPath = ({ itemClip, portrait }: GetClipPathProps): CSSProperties['clipPath'] => {
  if (itemClip === ReactCompareSliderClip.itemOne) {
    return portrait
      ? `inset(0px 0px calc(100% - var(${ReactCompareSliderCssVars.currentPosition})) 0px)`
      : `inset(0px calc(100% - var(${ReactCompareSliderCssVars.currentPosition})) 0px 0px)`;
  }

  if (itemClip === ReactCompareSliderClip.itemTwo) {
    return portrait
      ? `inset(var(${ReactCompareSliderCssVars.currentPosition}) 0px 0px 0px)`
      : `inset(0px 0px 0px var(${ReactCompareSliderCssVars.currentPosition}))`;
  }

  return 'none';
};

export type ItemsProps = ComponentProps<'div'> & {
  item?: Extract<ReactCompareSliderClipValue, 'itemOne' | 'itemTwo'>;
};

/**
 * Container for `itemOne` and `itemTwo`.
 */
export const Item: FC<ItemsProps> = ({ item, style, ...props }) => {
  const { clip, portrait } = useReactCompareSliderContext();

  const shouldClip = clip === ReactCompareSliderClip.all || clip === item;
  const itemClip = shouldClip ? item : undefined;

  const appliedStyle: CSSProperties = {
    KhtmlUserSelect: 'none',
    MozUserSelect: 'none',
    WebkitUserSelect: 'none',
    backfaceVisibility: 'hidden',
    WebkitBackfaceVisibility: 'hidden',
    gridArea: '1 / 1',
    maxWidth: '100%',
    overflow: 'hidden',
    clipPath: getClipPath({ itemClip, portrait }),
    boxSizing: 'border-box',
    transform: 'translateZ(0)',
    userSelect: 'none',
    zIndex: item === ReactCompareSliderClip.itemOne ? 1 : undefined,
    willChange: 'clip-path',
    ...style,
  };

  return <div data-rcs="item" data-rcs-item={item} {...props} style={appliedStyle} />;
};

'use client';

import { createContext, type PropsWithChildren, useContext } from 'react';

import type { UseReactCompareSliderReturn } from '../types';

export type ContextProps = UseReactCompareSliderReturn;

const Context = createContext<ContextProps | null>(null);

export type ProviderProps = PropsWithChildren<ContextProps>;

/**
 * The root component of the slider - provides the state and event handlers for the slider components.
 */
export const Provider: React.FC<ProviderProps> = ({ children, ...value }) => {
  return <Context.Provider value={value}>{children}</Context.Provider>;
};

/**
 * Access the state and event handlers of the slider - must be used within the `Provider` or `ReactCompareSlider` component.
 * @example
 * ```tsx
 * const { position, setPosition } = useReactCompareSliderContext();
 * ```
 */
export const useReactCompareSliderContext = (): ContextProps => {
  const context = useContext(Context);

  if (!context) {
    throw new Error('useReactCompareSliderContext must be used within the Provider component');
  }

  return context;
};

'use client';

import type { ComponentProps, CSSProperties, FC } from 'react';
import { useEffect } from 'react';

import { EVENT_CAPTURE_PARAMS, EVENT_PASSIVE_PARAMS, useEventListener } from './internal-hooks';
import { useReactCompareSliderContext } from './provider';
import { ReactCompareSliderCssVars } from '../consts';

export type RootProps = ComponentProps<'div'>;

const currentPositionCssValue = `clamp(var(${ReactCompareSliderCssVars.boundsPadding}), var(${ReactCompareSliderCssVars.rawPosition}) - var(${ReactCompareSliderCssVars.boundsPadding}) + var(${ReactCompareSliderCssVars.boundsPadding}), calc(100% - var(${ReactCompareSliderCssVars.boundsPadding})))`;

/**
 * The root container of the slider.
 */
export const Root: FC<RootProps> = ({ style, ...props }) => {
  const {
    browsingContext,
    boundsPadding,
    changePositionOnHover,
    clip,
    isDragging,
    portrait,
    position,
    onTouchEnd,
    onPointerDown,
    onPointerMove,
    onPointerUp,
    interactiveTarget,
    rootRef,
    transition,
    canTransition,
  } = useReactCompareSliderContext();

  const appliedStyle = {
    position: 'relative',
    boxSizing: 'border-box',
    display: 'grid',
    maxWidth: '100%',
    maxHeight: '100%',
    overflow: 'hidden',
    cursor: isDragging ? (portrait ? 'ns-resize' : 'ew-resize') : undefined,
    touchAction: portrait ? 'pan-x' : 'pan-y',
    userSelect: 'none',
    KhtmlUserSelect: 'none',
    msUserSelect: 'none',
    MozUserSelect: 'none',
    WebkitUserSelect: 'none',
    /**
     * The transition is on the root because this is where `--rcs-raw-position` is set.
     * With the `@property` registration in the hook, the browser interpolates the variable itself, so children
     * that reference it via `var()` see smooth intermediate values without needing their own transitions.
     * This improves performance and prevents Safari from desyncing independent transitions on separate elements.
     */
    transition:
      canTransition && transition ? `${ReactCompareSliderCssVars.rawPosition} ${transition}` : 'none',
    [ReactCompareSliderCssVars.rawPosition]: `${position.current}%`,
    [ReactCompareSliderCssVars.boundsPadding]: boundsPadding,
    [ReactCompareSliderCssVars.currentPosition]: currentPositionCssValue,
    ...style,
  } as CSSProperties;

  useEventListener('touchend', onTouchEnd, interactiveTarget, EVENT_CAPTURE_PARAMS);
  useEventListener('pointerdown', onPointerDown, interactiveTarget, EVENT_CAPTURE_PARAMS);

  // Handle hover events on the container.
  useEffect(() => {
    const containerRef = rootRef.current as HTMLDivElement;

    const handlePointerLeave = (ev: PointerEvent): void => {
      if (isDragging) return;
      onPointerUp(ev);
    };

    if (changePositionOnHover) {
      containerRef.addEventListener('pointermove', onPointerMove, EVENT_PASSIVE_PARAMS);
      containerRef.addEventListener('pointerleave', handlePointerLeave, EVENT_PASSIVE_PARAMS);
    }

    return () => {
      containerRef.removeEventListener('pointermove', onPointerMove);
      containerRef.removeEventListener('pointerleave', handlePointerLeave);
    };
  }, [changePositionOnHover, onPointerMove, onPointerUp, isDragging, rootRef]);

  // Allow drag outside of container while pointer is still down.
  useEffect(() => {
    if (!isDragging) return;

    browsingContext.addEventListener('pointermove', onPointerMove, EVENT_PASSIVE_PARAMS);
    browsingContext.addEventListener('pointerup', onPointerUp, EVENT_PASSIVE_PARAMS);

    return () => {
      browsingContext?.removeEventListener('pointermove', onPointerMove);
      browsingContext?.removeEventListener('pointerup', onPointerUp);
    };
  }, [onPointerMove, onPointerUp, isDragging, browsingContext]);

  return <div ref={rootRef} style={appliedStyle} data-rcs="root" data-rcs-clip={clip} {...props} />;
};

